-- Upcoming Programs CSV step (13 steps, first step of Part 2)
alter table orgs add column if not exists programs_upload_storage_path text;
alter table orgs add column if not exists programs_upload_original_filename text;
alter table orgs add column if not exists programs_uploaded_at timestamptz;

-- Shift existing step progress for canonical template orgs (new step inserted at index 6).
do $$
declare
  r record;
begin
  for r in
    select sp.id, sp.step_index
    from step_progress sp
    inner join orgs o on o.id = sp.org_id
    inner join templates t on t.id = o.template_id
    where sp.step_index >= 6
      and (t.is_default = true or lower(trim(t.name)) = lower('Onboarding Template'))
    order by sp.step_index desc
  loop
    update step_progress set step_index = step_index + 1 where id = r.id;
  end loop;
end $$;

insert into step_progress (org_id, step_index, completed)
select o.id, 6, false
from orgs o
inner join templates t on t.id = o.template_id
where t.is_default = true or lower(trim(t.name)) = lower('Onboarding Template')
on conflict (org_id, step_index) do nothing;

update templates
set
  meta = '{"kickoffDividerAfterStepIndex":5}'::jsonb,
  steps = $steps$
[{"title":"Connect Your Bank Account","time":"~5 min","description":"This is what allows you to start collecting payments from customers. Get this done first so everything else can be tested end to end.","links":[{"label":"Watch setup video","url":"https://jam.dev/c/b1815fb9-2d82-46ed-b75b-8416566440ec","icon":"Video"}],"doneWhen":"Done when your bank account shows as connected in Settings."},{"title":"List Your Rentable Spaces","time":"~10 min","description":"Use the CSV template to list courts, fields, ice time, cages, rooms, or any rentable spaces at your facility. Download the template, fill in your rows, and upload your file below. Bond will use this file during onboarding and setup.","links":[{"label":"Setting Up Rental Products (help)","url":"https://help.bondsports.co/en/articles/11021853-setting-up-rental-products","icon":"Guide"},{"label":"Rental Reservations Overview","url":"https://help.bondsports.co/en/articles/11403275-rental-reservations-overview","icon":"Guide"}],"spacesCsvUpload":true,"doneWhen":"Done when you have uploaded your spaces CSV and reviewed it for accuracy."},{"title":"Understand the Back Office","time":"~3 min","description":"Before diving into setup, spend a few minutes getting oriented with how Bond's back office is organized. Understanding the main navigation will make every step below much faster.","links":[{"label":"Back Office Overview","url":"https://help.bondsports.co/en/collections/11612167-getting-started","icon":"Book"}],"doneWhen":"Done when you've watched the overview and can find the main nav sections."},{"title":"Order Your Point of Sale Devices","time":"~5 min","description":"If you plan to take in-person payments, order the card readers and POS hardware Bond supports for your facility. Getting this started early avoids delays before go-live.","links":[{"label":"Contact Bond support to order POS hardware","url":"https://help.bondsports.co/en/collections/11612167-getting-started","icon":"Guide"}],"doneWhen":"Done when you have submitted a POS hardware order or confirmed you do not need in-person devices."},{"title":"Set Up Roles & Permissions","time":"~10 min","description":"Define the roles your staff will use in Bond — what each role can view and change in the back office. You will assign people to these roles in the next step.","links":[{"label":"Roles & Permissions Guide","url":"https://help.bondsports.co/en/articles/10128365-roles-permissions","icon":"Guide"}],"note":"Important: Incorrect permissions can affect security and daily operations. Take a few extra minutes to configure roles carefully.","doneWhen":"Done when your roles are created and reflect how your team actually works."},{"title":"Add Employees & Assign Roles","time":"~10 min","description":"Add each member of your staff to Bond and assign them the role you configured in the previous step.","links":[{"label":"Roles & Permissions Guide","url":"https://help.bondsports.co/en/articles/10128365-roles-permissions","icon":"Guide"}],"checklist":["Add all employees to the system","Assign the correct role to each person"],"doneWhen":"Done when all staff are added and roles are assigned."},{"title":"Upcoming Programs Template","time":"~10 min","description":"Download the CSV template and list the programs you plan to run — camps, leagues, classes, clinics, and training sessions. Fill in one row per program and upload your file below. Bond uses this during program setup after kickoff.","links":[{"label":"Programs Getting Started Guide","url":"https://help.bondsports.co/en/articles/11060636-getting-started","icon":"Guide"}],"programsCsvUpload":true,"doneWhen":"Done when you have uploaded your upcoming programs CSV and reviewed it for accuracy."},{"title":"Configure Your Tax Rates","time":"~5 min","description":"Set how taxes are applied to your products. You'll want this in place before creating rentals or programs.","links":[{"label":"Open Tax Settings","url":"https://backoffice.bondsports.co/client/settings#/organization/taxes/tax-rates","icon":"Settings"}],"checklist":["Exclusive tax, added on top of product price","Inclusive tax, built into the product price"],"optional":true,"doneWhen":"Done when your tax rates are saved in Settings."},{"title":"Upload a List of Your Accounting Codes","time":"~10 min","description":"Download the CSV template, list your GL / accounting codes, and upload the file below. Bond uses this during setup so reporting and product mapping stay aligned from day one.","links":[{"label":"Accounting Codes Guide","url":"https://help.bondsports.co/en/articles/12968674-accounting-codes","icon":"Guide"}],"glCodesCsvUpload":true,"optional":true,"doneWhen":"Done when you have uploaded your accounting codes CSV and reviewed it for accuracy."},{"title":"Set Up Rental Products","time":"~15 min","description":"Create your rental products, courts, fields, ice time, cages, or any bookable space at your facility. Program products will be set up together during your initial program training call with the Bond team.","links":[{"label":"Setting Up Rental Products","url":"https://help.bondsports.co/en/articles/11021853-setting-up-rental-products","icon":"Guide"},{"label":"Rental Reservations Overview","url":"https://help.bondsports.co/en/articles/11403275-rental-reservations-overview","icon":"Guide"}],"doneWhen":"Done when your rental products are created and visible in the back office."},{"title":"Set Up Programs (Registrations)","time":"~10 min","description":"Use programs for classes, leagues, camps, clinics, and training sessions — anything that requires participant registration rather than a simple rental booking.","links":[{"label":"Programs Getting Started Guide","url":"https://help.bondsports.co/en/articles/11060636-getting-started","icon":"Guide"}],"note":"Your Bond onboarding specialist will walk through program setup in detail on your training call. This step is here to help you get familiar beforehand.","doneWhen":"Done when you've reviewed the guide and are ready for your training call."},{"title":"Set Up Forms & Waivers","time":"~5 min","description":"Collect important participant information, waivers, and custom questionnaires — attached directly to your products and programs.","links":[{"label":"Forms & Waivers Guide","url":"https://help.bondsports.co/en/articles/13066858-managing-forms-questionnaires-in-the-bond-back-office","icon":"Guide"}],"doneWhen":"Done when at least one form or waiver is created and linked to a product."},{"title":"Enable Conversion Tracking","time":"~5 min","description":"Connect Bond to tools like Google Analytics (GA4) to track how customers are finding and completing registrations on your site. This is an advanced step — come back to it once your core setup is complete.","links":[{"label":"Conversion Analytics Guide","url":"https://help.bondsports.co/en/collections/12615606-conversion-analytics","icon":"Guide"}],"optional":true,"doneWhen":"Done when your GA4 or tracking pixel is connected and firing."}]
$steps$::jsonb
where is_default = true
   or lower(trim(name)) = lower('Onboarding Template');
